import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const h=JSON.parse('{"title":"ADR-014 — GitHub Actions CI + GitHub Pages as preview environment","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-014.md","filePath":"adr/ADR-014.md"}'),n={name:"adr/ADR-014.md"};function r(s,e,d,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-014-—-github-actions-ci-github-pages-as-preview-environment" tabindex="-1">ADR-014 — GitHub Actions CI + GitHub Pages as preview environment <a class="header-anchor" href="#adr-014-—-github-actions-ci-github-pages-as-preview-environment" aria-label="Permalink to &quot;ADR-014 — GitHub Actions CI + GitHub Pages as preview environment&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 Supersedes · ADR-005 (Docker Compose as sole deployment target) TA anchor · §stack</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Production deployment platform is not yet decided. In the interim, GitHub Actions provides CI and GitHub Pages provides a free preview environment accessible at <code>https://chipi.github.io/orrery</code>. Docker Compose remains valid for local development and self-hosted deployment.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>GitHub Actions for all CI (build, typecheck, lint, test, doc-check, asset fetch). GitHub Pages as the preview/staging environment on every push to <code>main</code>. Docker Compose retained for local development. Production hosting TBD.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>GitHub provides everything needed for free on a public repo: Actions minutes, Pages hosting, Dependabot, CodeQL. No third-party CI service needed. GitHub Pages serves the built static files from the <code>gh-pages</code> branch — same output that will go to production, just served from GitHub&#39;s CDN.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Cloudflare Pages</strong> — strong candidate for production; global edge CDN; free tier generous; deferred until production decision is made.</li><li><strong>Vercel</strong> — also strong; Next.js-native but supports SvelteKit; deferred.</li><li><strong>Netlify</strong> — valid; deferred.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: free; zero configuration beyond the Actions workflow; every push to main is instantly previewable at a real URL. Negative: GitHub Pages base path (<code>/orrery/</code>) requires <code>base: &#39;/orrery/&#39;</code> in <code>vite.config.ts</code> for GH Pages deploy — production deploy will not need this; manage via environment variable.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>Two workflows: <code>ci.yml</code> (on every push/PR: build, typecheck, lint, test) and <code>preview.yml</code> (on push to main: build + deploy to gh-pages branch). Base path conditional on <code>GITHUB_PAGES=true</code> env var.</p>',14)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
